// Generates src/brand-icons.ts from simple-icons (CC0-1.0). Run via:
//   node scripts/gen-brand-icons.mjs
// Only the curated brands below are inlined, so the runtime bundle ships just
// those icons (no dependency on simple-icons at runtime). Re-run to add brands
// or refresh paths after a simple-icons upgrade, then commit the generated file.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import * as simpleIcons from 'simple-icons';

// Popular brands for corporate-site social links / footers. Keep alphabetical.
// NOTE: LinkedIn is intentionally absent — it was removed from simple-icons at
// the brand's request, so it has no CC0 path to inline.
const SLUGS = [
  'apple', 'behance', 'discord', 'dribbble', 'facebook', 'github', 'google',
  'instagram', 'mastodon', 'medium', 'pinterest', 'reddit', 'snapchat',
  'spotify', 'telegram', 'tiktok', 'vimeo', 'whatsapp', 'x', 'youtube',
];

const bySlug = new Map();
for (const value of Object.values(simpleIcons)) {
  if (value && typeof value === 'object' && typeof value.slug === 'string') {
    bySlug.set(value.slug, value);
  }
}

const entries = [];
const missing = [];
for (const slug of [...SLUGS].sort()) {
  const icon = bySlug.get(slug);
  if (!icon) {
    missing.push(slug);
    continue;
  }
  entries.push({ slug, title: icon.title, hex: icon.hex.toLowerCase(), path: icon.path });
}
if (missing.length) throw new Error(`unknown simple-icons slugs: ${missing.join(', ')}`);

const rows = entries
  .map((e) => `  ['${e.slug}', { title: ${JSON.stringify(e.title)}, hex: '#${e.hex}', path: ${JSON.stringify(e.path)} }],`)
  .join('\n');

const out = `// AUTO-GENERATED by scripts/gen-brand-icons.mjs from simple-icons (CC0-1.0,
// https://simpleicons.org). DO NOT EDIT BY HAND — re-run the generator to change
// the curated set. Each entry is a brand logo as a single 24x24 FILL path (vs the
// stroke-based Lucide set in icons.ts); brand trademarks belong to their owners.

/** A brand (social) icon: a 24x24 fill path plus the brand's official hex color. */
export interface BrandIcon {
  /** Human-readable brand name (used as the default accessible label). */
  title: string;
  /** Official brand hex color (e.g. for an opt-in brand-colored render). */
  hex: string;
  /** The single SVG path \`d\` filling a 0 0 24 24 viewBox. */
  path: string;
}

const BRAND_ICONS = new Map<string, BrandIcon>([
${rows}
]);

/** Slugs of the built-in brand icons (for the editor's icon picker). */
export const BRAND_ICON_NAMES: readonly string[] = [...BRAND_ICONS.keys()];

/** The brand icon for a slug, or \`undefined\` if unknown. */
export function brandIcon(slug: string): BrandIcon | undefined {
  return BRAND_ICONS.get(slug);
}
`;

const dir = dirname(fileURLToPath(import.meta.url));
const target = join(dir, '..', 'src', 'brand-icons.ts');
writeFileSync(target, out);
console.log(`wrote ${entries.length} brand icons to ${target}`);
